import subprocess

def is_copilot_cli_installed():
    try:
        result = subprocess.run(
            ["gh", "copilot", "--version"],
            capture_output=True,
            text=True,
            check=True
        )
        return True, result.stdout.strip()
    except subprocess.CalledProcessError:
        return False, None
    except FileNotFoundError:
        return False, None

installed, version = is_copilot_cli_installed()
if installed:
    print(f"GitHub Copilot CLI is installed (Version: {version})")
else:
    print("GitHub Copilot CLI is not installed. Please install it from: https://github.com/github/copilot-cli")
